code_questions.solution_code:
function debounce(fn, delay) {
  let timer = null;
  function debounced(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => { fn.apply(this, args); timer = null; }, delay);
  }
  debounced.cancel = function() { clearTimeout(timer); timer = null; };
  return debounced;
}

