#include <iostream>
using namespace std;

class Node {
public:
    int value;
    Node* next;
    Node(int v) : value(v), next(nullptr) {}
};

void addNode(Node* head, int value) {
    Node* newNode = new Node(value);
    head->next = newNode;
}

void freeList(Node* head) {
    while (head != nullptr) {
        Node* temp = head;
        head = head->next;
        delete temp;
    }
}

int main() {
    Node* head = new Node(1);
    addNode(head, 2);
    addNode(head, 3);
    freeList(head);
    return 0;
}

